#include <SPI.h>
extern int sma_hysteresis_pid(float,float,float,float,float*,float*);
extern bool thermal_fault_check(float,float,int);
#define TC_CS 10
#define FET_PIN 9
#define BUZ_PIN 8
#define NTC_PIN A0
void spi_setup(){
  SPI.begin();
  pinMode(TC_CS,OUTPUT);
  digitalWrite(TC_CS,HIGH);}
float read_tc(){
  SPI.beginTransaction(SPISettings(5000000,MSBFIRST,SPI_MODE0));
  digitalWrite(TC_CS,LOW);delayMicroseconds(1);
  uint32_t d=0;
  for(int i=0;i<4;i++)d=(d<<8)|SPI.transfer(0);
  digitalWrite(TC_CS,HIGH);
  SPI.endTransaction();
  if(d&0x07)return -999.0f;
  return((int32_t)(d&0xFFFC0000)>>18)*0.25f;}
float read_ntc(){
  int raw=analogRead(NTC_PIN);
  float r=10000.0f*raw/(1023.0f-raw);
  return 1.0f/(log(r/10000.0f)/3950.0f+1.0f/298.15f)-273.15f;}
void fet_setup(){pinMode(FET_PIN,OUTPUT);}
void fet_set(int v){analogWrite(FET_PIN,constrain(v,0,255));}
static float ig=0,le=0;
float SP=68.0f;
unsigned long pt=0;
void setup(){
  Serial.begin(115200);
  spi_setup();fet_setup();
  pinMode(BUZ_PIN,OUTPUT);}
void loop(){
  unsigned long n=millis();
  float dt=(n-pt)/1000.0f;
  if(dt<0.1f)return;pt=n;
  float temp=read_tc();
  if(temp<-100.0f){temp=read_ntc();tone(BUZ_PIN,880,100);}
  if(thermal_fault_check(temp,80.0f,BUZ_PIN)){fet_set(0);return;}
  int pw=sma_hysteresis_pid(SP,temp,dt,temp,&ig,&le);
  fet_set(pw);
  Serial.print(temp,2);Serial.print(',');Serial.println(pw);}
